export const totalCareers = careers.length;
export const totalSubjects = subjects.length;
export const totalPathways = pathways.length;
export const totalSubTracks = subTracks.length;

export function getCareerById(id: number): Career | undefined {
  return careers.find(c => c.id === id);
}

export function getCareersBySubTrack(code: string): Career[] {
  return careers.filter(c => c.subTrackCode === code);
}

export function getCareersByPathway(code: string): Career[] {
  return careers.filter(c => c.pathwayCode === code);
}

export function getSubTracksByPathway(pathwayCode: string): SubTrack[] {
  return subTracks.filter(st => st.pathwayCode === pathwayCode);
}

export function getPathwayByCode(code: string): Pathway | undefined {
  return pathways.find(p => p.code === code);
}

export function getSubTrackByCode(code: string): SubTrack | undefined {
  return subTracks.find(st => st.code === code);
}

export function getCareerCountBySubTrack(code: string): number {
  return careers.filter(c => c.subTrackCode === code).length;
}

export function getCareerCountByPathway(code: string): number {
  return careers.filter(c => c.pathwayCode === code).length;
}